mapper.select:
SELECT *
FROM iot_thing_model
WHERE product_key = #{productKey}
  AND version = #{version}
  AND is_delete = 0
LIMIT 1

mapper.update:
UPDATE iot_thing_model
SET model_json = #{modelJson},
    updated_at = CURRENT_TIMESTAMP
WHERE product_key = #{productKey}
  AND version = #{version}
  AND is_delete = 0
